/**
 * Classification Result Interface
 * 
 * This interface defines the structure for classification results
 * generated by the Report Classification Engine.
 * 
 * PHASE 6 — Report Classification Engine
 * Required Systems: Report Intelligence System
 */

/**
 * Confidence score for classification results
 */
export interface ConfidenceScore {
  /** Overall confidence score (0-10) */
  overall: number;
  
  /** Confidence in document type classification (0-10) */
  documentType: number;
  
  /** Confidence in report type classification (0-10) */
  reportType: number;
  
  /** Confidence in industry classification (0-10) */
  industry: number;
  
  /** Confidence in purpose classification (0-10) */
  purpose: number;
  
  /** Confidence in style classification (0-10) */
  style: number;
  
  /** Confidence in complexity classification (0-10) */
  complexity: number;
  
  /** Confidence in quality assessment (0-10) */
  quality: number;
  
  /** Confidence in compliance assessment (0-10) */
  compliance: number;
  
  /** Confidence in risk assessment (0-10) */
  risk: number;
  
  /** Detailed confidence breakdown */
  breakdown: {
    /** Statistical confidence based on features */
    statistical: number;
    /** Semantic confidence based on content */
    semantic: number;
    /** Structural confidence based on format */
    structural: number;
    /** Historical confidence based on similar documents */
    historical: number;
  };
}

/**
 * Classification result for a document
 */
export interface ClassificationResult {
  /** Unique identifier for the classification result */
  id: string;
  
  /** Original document identifier */
  documentId: string;
  
  /** Classification timestamp */
  classifiedAt: Date;
  
  /** Classification version */
  version: string;
  
  /** Classification metadata */
  metadata: {
    /** Classification engine identifier */
    classificationEngine: string;
    /** Engine version */
    version: string;
    /** Processing timestamp */
    processedAt: string;
    /** Number of classifications performed */
    classificationCount: number;
    /** Source of the report */
    reportSource: string;
  };
  
  /** Document type classification */
  documentType: {
    /** Primary document type */
    primary: string;
    /** Alternative document types with scores */
    alternatives: Array<{
      type: string;
      confidence: number;
      score: number;
    }>;
    /** Document type description */
    description: string;
    /** Document type characteristics */
    characteristics: string[];
  };
  
  /** Report type classification */
  reportType: {
    /** Primary report type */
    primary: string;
    /** Alternative report types with scores */
    alternatives: Array<{
      type: string;
      confidence: number;
      score: number;
    }>;
    /** Report type description */
    description: string;
    /** Report type characteristics */
    characteristics: string[];
  };
  
  /** Industry classification */
  industry: {
    /** Primary industry */
    primary: string;
    /** Alternative industries with scores */
    alternatives: Array<{
      industry: string;
      confidence: number;
      score: number;
    }>;
    /** Industry description */
    description: string;
    /** Industry characteristics */
    characteristics: string[];
  };
  
  /** Purpose classification */
  purpose: {
    /** Primary purpose */
    primary: string;
    /** Alternative purposes with scores */
    alternatives: Array<{
      purpose: string;
      confidence: number;
      score: number;
    }>;
    /** Purpose description */
    description: string;
    /** Purpose characteristics */
    characteristics: string[];
  };
  
  /** Style classification */
  style: {
    /** Primary style */
    primary: string;
    /** Alternative styles with scores */
    alternatives: Array<{
      style: string;
      confidence: number;
      score: number;
    }>;
    /** Style description */
    description: string;
    /** Style characteristics */
    characteristics: string[];
  };
  
  /** Complexity classification */
  complexity: {
    /** Complexity level (simple, moderate, complex, very-complex) */
    level: 'simple' | 'moderate' | 'complex' | 'very-complex';
    /** Complexity score (0-100) */
    score: number;
    /** Complexity description */
    description: string;
    /** Complexity factors */
    factors: string[];
  };
  
  /** Quality assessment */
  quality: {
    /** Overall quality score (0-100) */
    score: number;
    /** Quality rating (excellent, good, fair, poor) */
    rating: 'excellent' | 'good' | 'fair' | 'poor';
    /** Quality description */
    description: string;
    /** Quality metrics */
    metrics: {
      /** Clarity score (0-100) */
      clarity: number;
      /** Accuracy score (0-100) */
      accuracy: number;
      /** Completeness score (0-100) */
      completeness: number;
      /** Consistency score (0-100) */
      consistency: number;
      /** Relevance score (0-100) */
      relevance: number;
      /** Readability score (0-100) */
      readability: number;
    };
    /** Quality issues */
    issues: string[];
  };
  
  /** Compliance assessment */
  compliance: {
    /** Overall compliance score (0-100) */
    score: number;
    /** Compliance status (compliant, non-compliant, partial) */
    status: 'compliant' | 'non-compliant' | 'partial';
    /** Compliance description */
    description: string;
    /** Compliance standards */
    standards: Array<{
      name: string;
      requirement: string;
      status: 'compliant' | 'non-compliant' | 'partial';
      score: number;
      details: string;
    }>;
    /** Compliance issues */
    issues: string[];
  };
  
  /** Risk assessment */
  risk: {
    /** Overall risk score (0-100) */
    score: number;
    /** Risk level (low, medium, high, critical) */
    level: 'low' | 'medium' | 'high' | 'critical';
    /** Risk description */
    description: string;
    /** Risk categories */
    categories: Array<{
      category: string;
      level: 'low' | 'medium' | 'high' | 'critical';
      score: number;
      description: string;
    }>;
    /** Risk factors */
    factors: string[];
  };
  
  /** Confidence scores */
  confidence: ConfidenceScore;
  
}

/**
 * Classification statistics
 */
export interface ClassificationStatistics {
  /** Total classifications performed */
  totalClassifications: number;
  
  /** Average classification time */
  averageClassificationTime: number;
  
  /** Average confidence score */
  averageConfidenceScore: number;
  
  /** Most common document types */
  commonDocumentTypes: Array<{
    type: string;
    count: number;
    percentage: number;
  }>;
  
  /** Most common report types */
  commonReportTypes: Array<{
    type: string;
    count: number;
    percentage: number;
  }>;
  
  /** Classification accuracy */
  accuracy: {
    overall: number;
    documentType: number;
    reportType: number;
    industry: number;
    purpose: number;
  };
  
  /** Classification errors */
  errors: Array<{
    type: string;
    count: number;
    percentage: number;
  }>;
}

/**
 * Classification suggestion
 */
export interface ClassificationSuggestion {
  /** Suggested classification */
  suggestion: string;
  
  /** Confidence in suggestion */
  confidence: number;
  
  /** Reason for suggestion */
  reason: string;
  
  /** Supporting evidence */
  evidence: string[];
  
  /** Alternative suggestions */
  alternatives: Array<{
    suggestion: string;
    confidence: number;
    reason: string;
  }>;
}

/**
 * Classification validation result
 */
export interface ClassificationValidation {
  /** Is classification valid */
  valid: boolean;
  
  /** Validation score (0-100) */
  score: number;
  
  /** Validation messages */
  messages: string[];
  
  /** Validation warnings */
  warnings: string[];
  
  /** Validation errors */
  errors: string[];
  
  /** Suggestions for improvement */
  suggestions: ClassificationSuggestion[];
}

/**
 * Classification type for document classification
 */
export interface ClassificationType {
  /** Primary classification */
  primary: string;
  /** Alternative classifications */
  alternatives: string[];
  /** Classification description */
  description: string;
  /** Classification characteristics */
  characteristics: string[];
}

/**
 * Complexity level for document complexity
 */
export type ComplexityLevel = 'basic' | 'intermediate' | 'advanced' | 'expert';

/**
 * Report schema for classification
 */
export interface ReportSchema {
  /** Schema name */
  name: string;
  /** Schema version */
  version: string;
  /** Schema fields */
  fields: Array<{
    /** Field name */
    name: string;
    /** Field type */
    type: string;
    /** Field required */
    required: boolean;
    /** Field description */
    description: string;
  }>;
  /** Schema validation rules */
  validation: Array<{
    /** Rule name */
    name: string;
    /** Rule condition */
    condition: string;
    /** Rule message */
    message: string;
  }>;
}